import java.util.*;

class FoodRatings {

    private Map<String, Integer> foodRatings;
    private Map<String, TreeSet<Food>> cuisineFoods;

    public FoodRatings(String[] foods, String[] cuisines, int[] ratings) {
        foodRatings = new HashMap<>();
        cuisineFoods = new HashMap<>();

        for (int i = 0; i < foods.length; i++) {
            foodRatings.put(foods[i], ratings[i]);

            cuisineFoods.computeIfAbsent(cuisines[i], k -> new TreeSet<>()).add(new Food(foods[i], ratings[i]));
        }
    }

    public void changeRating(String food, int newRating) {
        String cuisine = getCuisine(food);
        cuisineFoods.get(cuisine).remove(new Food(food, foodRatings.get(food)));
        cuisineFoods.get(cuisine).add(new Food(food, newRating));
        foodRatings.put(food, newRating);
    }

    public String highestRated(String cuisine) {
        return cuisineFoods.get(cuisine).first().name;
    }

    private String getCuisine(String food) {
        for (Map.Entry<String, TreeSet<Food>> entry : cuisineFoods.entrySet()) {
            if (entry.getValue().contains(new Food(food, 0))) {
                return entry.getKey();
            }
        }
        return null;
    }

    private static class Food implements Comparable<Food> {
        String name;
        int rating;

        Food(String name, int rating) {
            this.name = name;
            this.rating = rating;
        }

        @Override
        public int compareTo(Food other) {
            if (rating != other.rating) {
                return Integer.compare(other.rating, rating);
            }
            return name.compareTo(other.name);
        }

        @Override
        public boolean equals(Object o) {
            if (this == o) return true;
            if (o == null || getClass() != o.getClass()) return false;
            Food food = (Food) o;
            return name.equals(food.name);
        }
    }
}
